import os
from anthropic import Anthropic
from evals.api import CompletionFn, CompletionResult

class AnthropicChatResult(CompletionResult):
    def __init__(self, response: str):
        self._response = response

    def get_completions(self) -> list[str]:
        return [self._response]

class AnthropicCompletionFn(CompletionFn):
    """Wraps Claude models for use with OpenAI Evals."""

    def __init__(self, model: str = "claude-haiku-4-5-20251001", **kwargs):
        self.model = model
        self.client = Anthropic(api_key=os.environ["ANTHROPIC_API_KEY"])

    def __call__(self, prompt, **kwargs) -> AnthropicChatResult:
        # prompt is a list of dicts: [{"role": ..., "content": ...}]
        system = ""
        messages = []
        for msg in prompt:
            if msg["role"] == "system":
                system = msg["content"]
            else:
                messages.append({"role": msg["role"], "content": msg["content"]})

        response = self.client.messages.create(
            model=self.model,
            max_tokens=512,
            system=system,
            messages=messages,
        )
        return AnthropicChatResult(response.content[0].text)
